1	type Quote = { premium: number };
2	type Item = { type: string; cursed?: boolean; enchantment?: number };
3	
4	const PROCESSING_FEE = 5;
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  staff: 80,
8	  amulet: 60,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	const ALIKE_BLOCK_SIZE = 3;
14	const ALIKE_BLOCK_PREMIUM = 60;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const LOYALTY_DISCOUNT_RATE = 0.2;
20	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
21	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
22	
23	const basePremiumFor = (item: Item): number =>
24	  BASE_PREMIUM_BY_TYPE[item.type];
25	
26	const curseSurchargeRateFor = (item: Item): number =>
27	  item.cursed ? CURSE_SURCHARGE_RATE : 0;
28	
29	const enchantmentSurchargeRateFor = (item: Item): number =>
30	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
31	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE
32	    : 0;
33	
34	const totalSurchargeRateFor = (item: Item): number =>
35	  curseSurchargeRateFor(item) + enchantmentSurchargeRateFor(item);
36	
37	const itemPremiumFor = (item: Item): number =>
38	  basePremiumFor(item) * (1 + totalSurchargeRateFor(item));
39	
40	const sumItemPremiums = (items: Item[]): number =>
41	  items.reduce((sum, item) => sum + itemPremiumFor(item), 0);
42	
43	const isAlikeBlock = (items: Item[]): boolean =>
44	  items.length === ALIKE_BLOCK_SIZE &&
45	  items.every((item) => item.type === items[0].type);
46	
47	const componentsPremium = (items: Item[]): number =>
48	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
49	
50	type QuoteInput = {
51	  customer?: { yearsWithMHPCO: number };
52	  firstInsurance?: boolean;
53	  followUp?: boolean;
54	  items: Item[];
55	};
56	
57	const loyaltyDiscountRateFor = (input: QuoteInput): number =>
58	  (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD
59	    ? LOYALTY_DISCOUNT_RATE
60	    : 0;
61	
62	const firstInsuranceSurchargeRateFor = (input: QuoteInput): number =>
63	  input.firstInsurance ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
64	
65	const followUpDiscountRateFor = (input: QuoteInput): number =>
66	  input.followUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
67	
68	const policyAdjustmentRateFor = (input: QuoteInput): number =>
69	  firstInsuranceSurchargeRateFor(input) -
70	  loyaltyDiscountRateFor(input) -
71	  followUpDiscountRateFor(input);
72	
73	export const quote = (input: QuoteInput): Quote => {
74	  const componentsTotal = componentsPremium(input.items);
75	  const policyTotal = componentsTotal + componentsTotal * policyAdjustmentRateFor(input);
76	  return { premium: Math.ceil(policyTotal + PROCESSING_FEE) };
77	};
78	
79	export const claim = (_input: unknown): unknown => undefined;
